+  const status = (err as { status?: unknown })?.status;
+  const code = (err as { code?: unknown })?.code;
+  if (status || code) return `status=${status ?? "unknown"} code=${code ?? "unknown"}`;
+  return JSON.stringify(err, null, 2);
+}
